import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Chart } from 'react-chartjs-2';
import { useAuth } from '../hooks/useAuth';
import NotificationCenter from './NotificationCenter';
import LoadingSpinner from './LoadingSpinner';

const Dashboard = () => {
  const { user, logout } = useAuth();
  const [loading, setLoading] = useState(true);
  const [metrics, setMetrics] = useState({
    totalSales: 0,
    activeUsers: 0,
    inventoryLevels: 0,
  });

  useEffect(() => {
    // Simulate fetching data
    setTimeout(() => {
      setMetrics({
        totalSales: 12000,
        activeUsers: 150,
        inventoryLevels: 300,
      });
      setLoading(false);
    }, 2000);
  }, []);

  if (loading) return <LoadingSpinner />;

  return (
    <div className="max-w-6xl mx-auto px-4 py-6">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-white">Dashboard</h1>
        <button onClick={logout} className="px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 transition">
          Logout
        </button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-xl font-semibold text-white">Total Sales</h2>
          <p className="text-2xl text-indigo-400">${metrics.totalSales}</p>
        </div>
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-xl font-semibold text-white">Active Users</h2>
          <p className="text-2xl text-indigo-400">{metrics.activeUsers}</p>
        </div>
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-xl font-semibold text-white">Inventory Levels</h2>
          <p className="text-2xl text-indigo-400">{metrics.inventoryLevels}</p>
        </div>
      </div>
      <div className="bg-gray-800 p-6 rounded-xl shadow-md mb-6">
        <h2 className="text-xl font-semibold text-white mb-4">Sales Overview</h2>
        <Chart
          type="line"
          data={{
            labels: ['January', 'February', 'March', 'April', 'May', 'June'],
            datasets: [
              {
                label: 'Sales',
                data: [1200, 1900, 3000, 5000, 2300, 3200],
                borderColor: 'rgba(75, 192, 192, 1)',
                backgroundColor: 'rgba(75, 192, 192, 0.2)',
              },
            ],
          }}
        />
      </div>
      <NotificationCenter />
    </div>
  );
};

export default Dashboard;

