import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import LoadingSpinner from './LoadingSpinner';

interface Product {
  id: string;
  name: string;
  price: number;
  stock: number;
  category: string;
}

const ProductList = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simulate fetching products
    setTimeout(() => {
      setProducts([
        { id: '1', name: 'Product A', price: 29.99, stock: 100, category: 'Category 1' },
        { id: '2', name: 'Product B', price: 49.99, stock: 50, category: 'Category 2' },
        { id: '3', name: 'Product C', price: 19.99, stock: 200, category: 'Category 3' },
      ]);
      setLoading(false);
    }, 2000);
  }, []);

  if (loading) return <LoadingSpinner />;

  return (
    <div className="max-w-6xl mx-auto px-4 py-6">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-white">Product Management</h1>
        <Link to="/add-product" className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
          Add Product
        </Link>
      </div>
      {products.length === 0 ? (
        <div className="text-center text-gray-400">No products available. Start by adding a new product.</div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {products.map(product => (
            <div key={product.id} className="bg-gray-800 p-6 rounded-xl shadow-md">
              <h2 className="text-xl font-semibold text-white">{product.name}</h2>
              <p className="text-gray-400">Price: ${product.price}</p>
              <p className="text-gray-400">Stock: {product.stock}</p>
              <p className="text-gray-400">Category: {product.category}</p>
              <div className="mt-4">
                <Link to={`/edit-product/${product.id}`} className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-500 transition">
                  Edit
                </Link>
                <button className="ml-2 px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 transition">
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ProductList;
